#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Start with base SELECT query
    auto query = sqlgen::read<std::vector<Book>>;

    // Build WHERE condition dynamically
    auto where_condition = sqlgen::transpilation::Condition<sqlgen::Nothing>{};

    if (filters.title_keyword) {
        where_condition = where_condition && ("title"_c.like("%" + *filters.title_keyword + "%"));
    }

    if (filters.min_year) {
        where_condition = where_condition && ("year"_c >= *filters.min_year);
    }

    if (filters.genre) {
        where_condition = where_condition && ("genre"_c == *filters.genre);
    }

    if (filters.max_price) {
        where_condition = where_condition && ("price"_c <= *filters.max_price);
    }

    // Apply WHERE clause if any conditions exist
    if (!where_condition.template is<sqlgen::Nothing>()) {
        query = query | sqlgen::where(where_condition);
    }

    // Connect to database and execute query
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return {};
    }

    auto conn = *conn_result;
    auto result = query(conn);

    if (result) {
        return *result;
    } else {
        return {};
    }
}

}  // namespace query_search_books_by_criteria
