  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Create the Account table by writing an empty container
  auto write_result = sqlgen::write(std::vector<Account>{})(conn);
  if (!write_result) {
    return false;
  }

  // 3. Create update statement for Account with set operations
  auto update_stmt = sqlgen::update<Account>(
    "balance"_c.set(100.0),
    "status"_c.set("active")
  );

  // 4. Apply the update to the database
