  if (!update_result) {
    return false;
  }

  // 5. Verify changes by reading the updated records
  auto read_result = sqlgen::read<std::vector<Account>>(conn);
  if (!read_result) {
    return false;
  }

  auto accounts = *read_result;

  // Verify that at least one record was updated
  if (accounts.empty()) {
    return false;
  }

  // Verify that the balance was set to 100.0 and status to "active"
  for (const auto& account : accounts) {
